class Solution(object):
    def isReachableAtTime(self, sx, sy, fx, fy, t):
        dx = abs(fx - sx)
        dy = abs(fy - sy)
        min_steps = max(dx, dy)  # Chebyshev distance
        if dx == 0 and dy == 0:
            return t == 0 or t >= 2  # can go out and come back, but t=1 is impossible at same cell (must move)
            # Actually: if same cell, t=0 trivially true; t=1 means must move away and can't return
        return t >= min_steps
